import { getMcpAgentRuntimeState } from "@/lib/mcp-agent/server/runtime";
import { McpAgentWorkspace } from "./mcp-agent-workspace";

export function McpAgentScreen() {
  const runtimeState = getMcpAgentRuntimeState();

  return (
    <main className="min-h-svh bg-background text-foreground">
      <div className="mx-auto flex w-full max-w-7xl flex-col gap-6 px-4 py-6 md:px-6">
        <header className="grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end">
          <div className="space-y-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Demo / MCP Runtime Doctor Agent
            </p>
            <h1 className="max-w-3xl font-medium text-2xl tracking-tight">
              Ask one agent to inspect project docs and local Next.js runtime
              state through MCP
            </h1>
            <p className="max-w-3xl text-muted-foreground text-sm/relaxed">
              This workspace connects AI SDK MCP clients to a built-in project
              docs server and an optional Next.js dev MCP server, then exposes
              the discovered tools to a ToolLoopAgent.
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <Badge variant="outline">{runtimeState.statusLabel}</Badge>
            <Badge variant="outline">{runtimeState.chatModel}</Badge>
          </div>
        </header>

        <div className="lg:h-svh">
          <McpAgentWorkspace
            chatModel={runtimeState.chatModel}
            configuredServers={runtimeState.configuredServers}
            configuredTools={runtimeState.configuredTools}
            isChatAvailable={runtimeState.isChatAvailable}
            nodeVersion={runtimeState.nodeVersion}
            setupMessage={runtimeState.setupMessage}
          />
        </div>
      </div>
    </main>
  );
}

"use client";

import { StopIcon, WrenchIcon } from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import type { McpAgentRuntimeState } from "@/lib/mcp-agent/server/runtime";
import { McpAgentAssistantTrace } from "./mcp-agent-assistant-trace";
import { getTextContent, mcpAgentSamplePrompts } from "./mcp-agent-model";
import { McpRuntimeSidebar } from "./mcp-runtime-sidebar";
import { useMcpAgentChat } from "./use-mcp-agent-chat";

interface McpAgentWorkspaceProps {
  chatModel: string;
  configuredServers: McpAgentRuntimeState["configuredServers"];
  configuredTools: McpAgentRuntimeState["configuredTools"];
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
}

export function McpAgentWorkspace({
  chatModel,
  configuredServers,
  configuredTools,
  isChatAvailable,
  nodeVersion,
  setupMessage,
}: McpAgentWorkspaceProps) {
  const {
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useMcpAgentChat();

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_22rem] lg:grid-rows-[minmax(0,1fr)]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {error ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {error.message}
          </div>
        ) : null}

        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-4xl flex-1 gap-6 px-4 pt-6 pb-[3lh]">
            {hasMessages ? (
              messages.map((message, index) => (
                <Message from={message.role} key={message.id}>
                  <MessageContent
                    className={cn(
                      "space-y-4",
                      message.role === "assistant" ? "max-w-4xl" : "max-w-2xl"
                    )}
                  >
                    {message.role === "assistant" ? (
                      <McpAgentAssistantTrace
                        isLastMessage={index === messages.length - 1}
                        isStreaming={isBusy}
                        message={message}
                      />
                    ) : (
                      <MessageResponse>
                        {getTextContent(message)}
                      </MessageResponse>
                    )}
                  </MessageContent>
                </Message>
              ))
            ) : (
              <ConversationEmptyState
                description="Ask about project docs, demo planning, or the local Next.js runtime. The agent will choose the relevant MCP tools without a mode switch."
                icon={<WrenchIcon className="size-5" />}
                title="MCP tool workspace is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-4xl">
            <PromptInput onSubmit={({ text }) => sendMessage({ text })}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Ask about project docs, demos, or local Next.js runtime state."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">ToolLoopAgent</Badge>
                  <Badge variant="outline">MCP</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isBusy ? (
                    <Button
                      onClick={stop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <StopIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      onClick={() => regenerate()}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!isChatAvailable}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {mcpAgentSamplePrompts.map((prompt) => (
                  <Button
                    key={prompt}
                    onClick={() => sendMessage({ text: prompt })}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <WrenchIcon className="size-3.5" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <McpRuntimeSidebar
        configuredServers={configuredServers}
        configuredTools={configuredTools}
        nodeVersion={nodeVersion}
      />
    </div>
  );
}

"use client";

import { MessageResponse } from "@/components/ai-elements/message";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import { Shimmer } from "@/components/ai-elements/shimmer";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
} from "@/components/ai-elements/tool";
import type { UIMessage } from "ai";

import {
  getReasoningText,
  getTextContent,
  getToolParts,
} from "./mcp-agent-model";

interface McpAgentAssistantTraceProps {
  isLastMessage: boolean;
  isStreaming: boolean;
  message: UIMessage;
}

export function McpAgentAssistantTrace({
  isLastMessage,
  isStreaming,
  message,
}: McpAgentAssistantTraceProps) {
  const text = getTextContent(message);
  const reasoningText = getReasoningText(message);
  const toolParts = getToolParts(message);
  const hasReasoning = reasoningText.length > 0;
  const hasText = text.length > 0;
  const lastPart = message.parts.at(-1);
  const isReasoningStreaming =
    isLastMessage && isStreaming && lastPart?.type === "reasoning";
  const showThinking =
    isLastMessage && isStreaming && !hasReasoning && !hasText;

  return (
    <>
      {hasReasoning ? (
        <Reasoning className="w-full" isStreaming={isReasoningStreaming}>
          <ReasoningTrigger />
          <ReasoningContent>{reasoningText}</ReasoningContent>
        </Reasoning>
      ) : null}

      {toolParts.map((part) => (
        <Tool key={part.toolCallId}>
          {part.type === "dynamic-tool" ? (
            <ToolHeader
              state={part.state}
              toolName={part.toolName}
              type={part.type}
            />
          ) : (
            <ToolHeader state={part.state} type={part.type} />
          )}
          <ToolContent>
            {part.input ? <ToolInput input={part.input} /> : null}
            <ToolOutput errorText={part.errorText} output={part.output} />
          </ToolContent>
        </Tool>
      ))}

      {hasText ? <MessageResponse>{text}</MessageResponse> : null}
      {showThinking ? <Shimmer className="text-sm">Thinking...</Shimmer> : null}
    </>
  );
}

import { isReasoningUIPart, isToolUIPart, type UIMessage } from "ai";

export const mcpAgentSamplePrompts = [
  "Review the project docs and tell me what MCP agent demo should cover.",
  "Check the local Next.js runtime for current errors, then explain what you found.",
  "List the ready demos and recommend the next checklist item.",
] as const;

export function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

export function getReasoningText(message: UIMessage) {
  return message.parts
    .filter(isReasoningUIPart)
    .map((part) => part.text)
    .join("\n\n");
}

export function getToolParts(message: UIMessage) {
  return message.parts.filter(isToolUIPart);
}

