function resolveNextDevtoolsMcpBin() {
  const packageJsonPath = requireFromHere.resolve(
    "next-devtools-mcp/package.json"
  );

  return path.join(path.dirname(packageJsonPath), "dist/index.js");
}

async function createProjectDocsClient(origin: string) {
  return await createMCPClient({
    clientName: "mcp-agent-project-docs-client",
    transport: {
      type: "http",
      url: new URL("/api/demos/mcp-agent/mcp", origin).toString(),
    },
  });
}

async function createNextRuntimeClient() {
  return await createMCPClient({
    clientName: "mcp-agent-nextjs-runtime-client",
    transport: new Experimental_StdioMCPTransport({
      args: [resolveNextDevtoolsMcpBin()],
      command: process.execPath,
      stderr: "pipe",
    }),
  });
}

async function appendClientTools({
  client,
  clients,
  prefix,
  serverName,
  summaries,
  tools,
  transport,
}: {
  client: MCPClient;
  clients: MCPClient[];
  prefix: string;
  serverName: string;
  summaries: McpServerSummary[];
  tools: ToolSet;
  transport: "http" | "stdio";
}) {
  clients.push(client);
  const rawTools = (await client.tools()) as ToolSet;
  const namespacedTools = namespaceMcpTools(prefix, rawTools);
  const toolNames = Object.keys(namespacedTools);

  Object.assign(tools, namespacedTools);
  summaries.push({
    instructions: client.instructions,
    name: serverName,
    status: "ready",
    toolNames,
    transport,
  });
}

function errorReason(error: unknown) {
  return error instanceof Error
    ? error.message
    : "Unknown MCP connection error.";
}

export async function createMcpAgentToolbox({
  origin,
}: {
  origin: string;
}): Promise<McpToolbox> {
  const clients: MCPClient[] = [];
  const summaries: McpServerSummary[] = [];
  const tools: ToolSet = {};

  await appendClientTools({
    client: await createProjectDocsClient(origin),
    clients,
    prefix: "project",
    serverName: "project-docs",
    summaries,
    tools,
    transport: "http",
  });

  try {
    await appendClientTools({
      client: await createNextRuntimeClient(),
      clients,
      prefix: "nextjs",
      serverName: "nextjs-runtime",
      summaries,
      tools,
      transport: "stdio",
    });
  } catch (error) {
    summaries.push({
      name: "nextjs-runtime",
      reason: errorReason(error),
      status: "unavailable",
      toolNames: [],
      transport: "stdio",
    });
  }

  return {
    close: () => closeMcpClients(clients),
    summary: createMcpRuntimeSummary(summaries),
    tools,
  };
}

import type { MCPClient } from "@ai-sdk/mcp";
import type { ToolSet } from "ai";

export type McpServerStatus = "ready" | "unavailable";
export type McpTransportKind = "http" | "stdio";

export interface McpServerSummary {
  instructions?: string;
  name: string;
  reason?: string;
  status: McpServerStatus;
  toolNames: string[];
  transport: McpTransportKind;
}

export interface McpRuntimeSummary {
  availableTools: string[];
  servers: McpServerSummary[];
}

export interface McpToolbox {
  close: () => Promise<void>;
  summary: McpRuntimeSummary;
  tools: ToolSet;
}

export function namespaceMcpTools(prefix: string, tools: ToolSet): ToolSet {
  return Object.fromEntries(
    Object.entries(tools).map(([name, tool]) => [`${prefix}__${name}`, tool])
  );
}

export function createMcpRuntimeSummary(
  servers: McpServerSummary[]
): McpRuntimeSummary {
  return {
    availableTools: servers.flatMap((server) => server.toolNames),
    servers,
  };
}

export function formatMcpRuntimeSummary(summary: McpRuntimeSummary): string {
  return summary.servers
    .map((server) => {
      const header = `${server.name} [${server.status}, ${server.transport}]`;
      const statusLine =
        server.status === "ready"
          ? header
          : `${header}: ${server.reason ?? "Unavailable."}`;
      const toolLines =
        server.toolNames.length > 0
          ? server.toolNames.map((toolName) => `- ${toolName}`).join("\n")
          : "- no tools available";
      const instructions = server.instructions
        ? `\nInstructions: ${server.instructions}`
        : "";

      return `${statusLine}${instructions}\nTools:\n${toolLines}`;
    })
    .join("\n\n");
}

export async function closeMcpClients(clients: MCPClient[]) {
  await Promise.allSettled(clients.map((client) => client.close()));
}

