const jsonText = (value: unknown) => ({
  content: [
    {
      text: JSON.stringify(value, null, 2),
      type: "text" as const,
    },
  ],
});

export function createProjectDocsMcpServer() {
  const server = new McpServer(
    {
      name: "mcp-agent-project-docs",
      title: "MCP Agent Project Docs",
      version: "0.1.0",
    },
    {
      instructions:
        "Use these tools for repository docs, demo catalog, and AI SDK recipes checklist questions.",
    }
  );

  server.registerTool(
    "list_demos",
    {
      description:
        "List demo catalog entries, optionally filtered by status or pattern.",
      inputSchema: {
        pattern: z.enum(projectDemoPatterns).optional(),
        status: z.enum(projectDemoStatuses).optional(),
      },
    },
    async ({ pattern, status }) =>
      jsonText(await listDemoCatalogForMcp({ pattern, status }))
  );

  server.registerTool(
    "read_demo_docs",
    {
      description:
        "Read durable docs and the feature README for one demo slug when present.",
      inputSchema: {
        slug: z.string().min(1),
      },
    },
    async ({ slug }) => jsonText(await readDemoDocsForMcp({ slug }))
  );

  server.registerTool(
    "search_project_docs",
    {
      description: "Search durable project docs for line-level matches.",
      inputSchema: {
        limit: z.number().int().min(1).max(30).optional(),
        query: z.string().min(1),
      },
    },
    async ({ limit, query }) =>
      jsonText(await searchProjectDocsForMcp({ limit, query }))
  );

  return server;
}

export async function handleProjectDocsMcpRequest(request: Request) {
  const server = createProjectDocsMcpServer();
  const transport = new WebStandardStreamableHTTPServerTransport({
    enableJsonResponse: true,
    sessionIdGenerator: undefined,
  });

  await server.connect(transport);

  try {
    return await transport.handleRequest(request);
  } finally {
    await server.close();
  }
}

import { existsSync } from "node:fs";
import { readFile } from "node:fs/promises";
import path from "node:path";
import {
  findProjectRoot,
  listProjectDocsSearchPaths,
  loadProjectDocsCatalog,
  type ProjectDocsCatalogEntry,
  type ProjectDemoPattern,
  type ProjectDemoStatus,
} from "./project-docs-catalog";

export interface ProjectDocFile {
  content: string;
  path: string;
}

export interface DemoDocsBundle {
  files: ProjectDocFile[];
  meta: ProjectDocsCatalogEntry;
  slug: string;
}

export interface ProjectDocSearchMatch {
  line: number;
  path: string;
  text: string;
}

export const projectMcpToolDefinitions = [
  {
    description:
      "List demo catalog entries, optionally filtered by status or pattern.",
    name: "list_demos",
  },
  {
    description:
      "Read the durable docs bundle for one demo slug, including docs/frontend and feature README when present.",
    name: "read_demo_docs",
  },
  {
    description:
      "Search the project docs system for concise line-level matches.",
    name: "search_project_docs",
  },
] as const;

async function readRepoFile(
  relativePath: string,
  root = findProjectRoot()
): Promise<ProjectDocFile | null> {
  const absolutePath = path.join(root, relativePath);

  if (!existsSync(absolutePath)) {
    return null;
  }

  return {
    content: await readFile(absolutePath, "utf8"),
    path: path.relative(root, absolutePath),
  };
}

export async function listDemoCatalogForMcp({
  pattern,
  status,
}: {
  pattern?: ProjectDemoPattern;
  status?: ProjectDemoStatus;
} = {}) {
  const catalog = await loadProjectDocsCatalog();

  return catalog
    .filter((entry) => (status ? entry.status === status : true))
    .filter((entry) => (pattern ? entry.pattern === pattern : true))
    .map((entry) => ({
      href: entry.status === "ready" ? entry.href : undefined,
      pattern: entry.pattern,
      slug: entry.slug,
      source: entry.source,
      status: entry.status,
      summary: entry.summary,
      title: entry.title,
    }));
}

export async function readDemoDocsForMcp({
  slug,
}: {
  slug: string;
}): Promise<DemoDocsBundle> {
  const root = findProjectRoot();
  const catalog = await loadProjectDocsCatalog(root);
  const meta = catalog.find((entry) => entry.slug === slug);

  if (!meta) {
    throw new Error(`Unknown demo slug: ${slug}`);
  }

  const candidatePaths = [meta.docsPath, meta.readmePath].filter(
    (candidate): candidate is string => Boolean(candidate)
  );
  const files = (
    await Promise.all(
      candidatePaths.map((candidate) => readRepoFile(candidate, root))
    )
  ).filter((file): file is ProjectDocFile => Boolean(file));

  if (files.length === 0) {
    throw new Error(`No durable docs were found for demo slug: ${slug}`);
  }

  return {
    files,
    meta,
    slug,
  };
}

export async function searchProjectDocsForMcp({
  limit = 12,
  query,
}: {
  limit?: number;
  query: string;
}) {
  const normalizedQuery = query.trim().toLowerCase();

  if (!normalizedQuery) {
    throw new Error("Expected a non-empty docs search query.");
  }

  const matches: ProjectDocSearchMatch[] = [];
  const root = findProjectRoot();
  const docsSearchPaths = await listProjectDocsSearchPaths(root);

  for (const docsPath of docsSearchPaths) {
    const file = await readRepoFile(docsPath, root);

    if (!file) {
      continue;
    }

    file.content.split("\n").forEach((line, index) => {
      if (
        matches.length < limit &&
        line.toLowerCase().includes(normalizedQuery)
      ) {
        matches.push({
          line: index + 1,
          path: file.path,
          text: line.trim(),
        });
      }
    });
  }

  return {
    matches,
    query,
  };
}

import { type UIMessage, validateUIMessages } from "ai";
import { getMcpAgentEnv, getMcpAgentSetupState } from "./env";
import { streamMcpAgent } from "./chat";
import { projectMcpToolDefinitions } from "./project-tools";

type DemoEnv = Record<string, string | undefined>;

interface McpAgentRequestBody {
  id?: string;
  messages?: UIMessage[];
}

interface StreamMcpAgentOptions {
  origin: string;
  sessionId: string;
}

interface McpAgentRequestDependencies {
  streamMcpAgent: (
    messages: UIMessage[],
    options: StreamMcpAgentOptions
  ) => Promise<Response> | Response;
}

export interface ConfiguredMcpServer {
  description: string;
  name: string;
  requiredSetup: string;
  transport: "http" | "stdio";
}

export interface McpAgentRuntimeState {
  chatModel: string;
  configuredServers: ConfiguredMcpServer[];
  configuredTools: { description: string; name: string; server: string }[];
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  statusLabel: "Ready" | "Setup required";
}

const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';
const invalidChatIdError =
  'Expected a JSON body with an "id" string and a "messages" array.';

export const configuredMcpServers: ConfiguredMcpServer[] = [
  {
    description:
      "Repository-local MCP server for demo catalog, project docs, and checklist evidence.",
    name: "project-docs",
    requiredSetup: "Built in",
    transport: "http",
  },
  {
    description:
      "Optional local Next.js development MCP server for route, log, and runtime diagnostics.",
    name: "nextjs-runtime",
    requiredSetup: "Run a Next.js dev server for the target app",
    transport: "stdio",
  },
];

export const configuredMcpTools = [
  ...projectMcpToolDefinitions.map((tool) => ({
    description: tool.description,
    name: `project__${tool.name}`,
    server: "project-docs",
  })),
  {
    description:
      "Discovered from next-devtools-mcp when a compatible Next.js dev server is running.",
    name: "nextjs__*",
    server: "nextjs-runtime",
  },
];

async function readMcpAgentRequest(
  body: unknown
): Promise<{ messages: UIMessage[]; sessionId: string }> {
  const { id, messages } = (body ?? {}) as McpAgentRequestBody;

  if (!(typeof id === "string" && id.length > 0 && Array.isArray(messages))) {
    throw new Error(invalidChatIdError);
  }

  try {
    return {
      messages: await validateUIMessages({ messages }),
      sessionId: id,
    };
  } catch {
    throw new Error(invalidUiMessagesError);
  }
}

export function getMcpAgentRuntimeState(
  env: DemoEnv = getMcpAgentEnv()
): McpAgentRuntimeState {
  const setup = getMcpAgentSetupState(env);
  const issues = [...setup.issues];

  return {
    chatModel: setup.config.chatModel,
    configuredServers: configuredMcpServers,
    configuredTools: configuredMcpTools,
    isChatAvailable: issues.length === 0,
    nodeVersion: setup.nodeVersion,
    setupMessage: issues.length > 0 ? issues.join(" ") : null,
    statusLabel: issues.length === 0 ? "Ready" : "Setup required",
  };
}

export async function handleMcpAgentRequest(
  request: Request,
  env: DemoEnv = getMcpAgentEnv(),
  dependencies: Partial<McpAgentRequestDependencies> = {
    streamMcpAgent: (messages, options) =>
      streamMcpAgent(messages, {
        env,
        origin: options.origin,
      }),
  }
) {
  const streamAgent =
    dependencies.streamMcpAgent ??
    ((messages: UIMessage[], options: StreamMcpAgentOptions) =>
      streamMcpAgent(messages, {
        env,
        origin: options.origin,
      }));
  const runtimeState = getMcpAgentRuntimeState(env);

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  try {
    const { messages, sessionId } = await readMcpAgentRequest(
      await request.json()
    );

    return streamAgent(messages, {
      origin: new URL(request.url).origin,
      sessionId,
    });
  } catch (error) {
    if (
      error instanceof Error &&
      [invalidUiMessagesError, invalidChatIdError].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }
}
